-- Seed: Tenancy Agreement, Nigeria — the first live Template-tier document.
-- Content reflects common Nigerian residential tenancy practice (yearly
-- rent, agency/legal fees, rent review, quiet enjoyment, forfeiture on
-- default). Not a substitute for a state Tenancy Law review — several
-- states (notably Lagos, under the Lagos Tenancy Law 2011) impose specific
-- notice periods and rent-recovery rules that should be checked for
-- high-value or contested tenancies.

insert into document_templates
  (document_type, country, title, intro, sections, signatures, fields, legal_note, seo_intro, status)
values (
  'tenancy-agreement',
  'ng',
  'TENANCY AGREEMENT',
  'This Tenancy Agreement sets out the terms on which the Landlord agrees to let, and the Tenant agrees to take, the property described below.',
  '[{"heading":"1. PARTIES","body":"This Tenancy Agreement (\"Agreement\") is made on {{agreementDate}} between:\n\nLANDLORD: {{landlordName}}, of {{landlordAddress}}, phone {{landlordPhone}} (\"Landlord\"); and\n\nTENANT: {{tenantName}}, of {{tenantAddress}}, phone {{tenantPhone}} (\"Tenant\").\n\nThe Landlord and Tenant are together referred to as the \"Parties.\""},{"heading":"2. PROPERTY","body":"The Landlord agrees to let to the Tenant the property described as:\n\n{{propertyDescription}}\n\nlocated at {{propertyAddress}} (the \"Property\"), for use as a private residence only."},{"heading":"3. TERM","body":"The tenancy shall run for a term of {{tenancyTerm}}, commencing on {{startDate}} and ending on {{endDate}}, unless renewed or terminated earlier in accordance with this Agreement."},{"heading":"4. RENT","body":"The annual rent for the Property is NGN {{annualRent}} (the \"Rent\"), payable {{paymentFrequency}} in advance. The Tenant acknowledges payment of NGN {{amountPaidAtSigning}} on signing this Agreement, covering the period stated above."},{"heading":"5. AGENCY, LEGAL AND CAUTION FEES","body":"In addition to the Rent, the Tenant has paid: Agency Fee of NGN {{agencyFee}}; Legal Fee of NGN {{legalFee}}; and a refundable Caution/Security Deposit of NGN {{cautionDeposit}}, held by the Landlord against damage to the Property beyond fair wear and tear, and refundable within a reasonable period after the Tenant vacates, less any deductions properly owed."},{"heading":"6. TENANT''S OBLIGATIONS","body":"The Tenant agrees to: (a) pay the Rent and any agreed service charge promptly when due; (b) use the Property only as a private residence and not for any illegal or commercial purpose without the Landlord''s written consent; (c) keep the Property in good and tenantable condition, fair wear and tear excepted; (d) not make structural alterations without the Landlord''s prior written consent; (e) not sublet or assign the tenancy without the Landlord''s prior written consent; and (f) allow the Landlord or the Landlord''s agent reasonable access to inspect the Property on reasonable notice."},{"heading":"7. LANDLORD''S OBLIGATIONS","body":"The Landlord agrees to: (a) ensure the Tenant has quiet enjoyment of the Property throughout the tenancy without unlawful interference; (b) keep the structure, roof, and major installations of the Property in reasonable repair, except where damage is caused by the Tenant''s default; and (c) refund the Caution Deposit (less any lawful deductions) within a reasonable period after the Tenant vacates and the Property is inspected."},{"heading":"8. RENT REVIEW AND RENEWAL","body":"Any renewal of this tenancy, and any review of the Rent on renewal, shall be by mutual written agreement between the Parties. Neither Party is obliged to renew this tenancy at the end of the term."},{"heading":"9. TERMINATION AND FORFEITURE","body":"If the Tenant fails to pay Rent when due, or breaches any material term of this Agreement and does not remedy the breach within a reasonable period after written notice, the Landlord may, subject to applicable tenancy law and after giving the notice required by law, recover possession of the Property. Nothing in this clause removes the Landlord''s obligation to follow the statutory notice-to-quit and recovery-of-premises process applicable in the state where the Property is located."},{"heading":"10. GOVERNING LAW","body":"This Agreement shall be governed by the tenancy laws applicable in the state where the Property is located, and the laws of the Federal Republic of Nigeria generally."},{"heading":"11. ENTIRE AGREEMENT","body":"This Agreement constitutes the entire understanding between the Parties concerning the tenancy and supersedes all prior discussions, representations, or agreements, whether oral or written."}]'::jsonb,
  '[{"role":"Landlord"},{"role":"Witness to Landlord"},{"role":"Tenant"},{"role":"Witness to Tenant"}]'::jsonb,
  '[{"id":"agreementDate","label":"Date of Agreement","type":"date","placeholder":"","required":true},{"id":"landlordName","label":"Landlord''s Full Name","type":"text","placeholder":"","required":true},{"id":"landlordAddress","label":"Landlord''s Address","type":"text","placeholder":"","required":true},{"id":"landlordPhone","label":"Landlord''s Phone Number","type":"text","placeholder":"","required":true},{"id":"tenantName","label":"Tenant''s Full Name","type":"text","placeholder":"","required":true},{"id":"tenantAddress","label":"Tenant''s Current Address","type":"text","placeholder":"","required":true},{"id":"tenantPhone","label":"Tenant''s Phone Number","type":"text","placeholder":"","required":true},{"id":"propertyDescription","label":"Property Description","type":"textarea","placeholder":"e.g. A 3-bedroom flat on the first floor","required":true},{"id":"propertyAddress","label":"Property Address","type":"text","placeholder":"","required":true},{"id":"tenancyTerm","label":"Tenancy Term","type":"text","placeholder":"e.g. 1 year","required":true},{"id":"startDate","label":"Start Date","type":"date","placeholder":"","required":true},{"id":"endDate","label":"End Date","type":"date","placeholder":"","required":true},{"id":"annualRent","label":"Annual Rent (₦)","type":"text","placeholder":"e.g. 1,500,000","required":true},{"id":"paymentFrequency","label":"Payment Frequency","type":"text","placeholder":"e.g. yearly","required":true},{"id":"amountPaidAtSigning","label":"Amount Paid at Signing (₦)","type":"text","placeholder":"","required":true},{"id":"agencyFee","label":"Agency Fee (₦)","type":"text","placeholder":"","required":false},{"id":"legalFee","label":"Legal Fee (₦)","type":"text","placeholder":"","required":false},{"id":"cautionDeposit","label":"Caution/Security Deposit (₦)","type":"text","placeholder":"","required":false}]'::jsonb,
  'Tenancy law varies by state — Lagos, for example, applies the Lagos Tenancy Law 2011, which sets specific notice periods before a landlord can recover possession. This template covers common Nigerian residential terms but is not a substitute for state-specific legal advice on notice periods or rent recovery.',
  'A Tenancy Agreement is the written record of the terms between a landlord and tenant in Nigeria — the property, the rent, the term, and each party''s obligations. It protects both sides: the landlord has a clear basis to enforce rent payment and property care, and the tenant has a clear record of what they''ve paid and what they''re entitled to, including quiet enjoyment of the property for the agreed term. Fill in the details below to generate a properly formatted Tenancy Agreement you can review, sign, and keep.',
  'published'
)
on conflict (document_type, country) do update set
  title = excluded.title,
  intro = excluded.intro,
  sections = excluded.sections,
  signatures = excluded.signatures,
  fields = excluded.fields,
  legal_note = excluded.legal_note,
  seo_intro = excluded.seo_intro,
  status = excluded.status;
